/* freelancer-stats.component.scss */
/* Styles for the component */

.freelancer-stats-container {
  max-width: 800px;
  margin: 0 auto;
  padding: 20px;

  h2 {
    text-align: center;
    color: #333;
  }

  .stats-form {
    display: flex;
    flex-direction: column;
    gap: 15px;
    margin-bottom: 30px;
    padding: 20px;
    border: 1px solid #ddd;
    border-radius: 8px;
    background-color: #f9f9f9;

    .form-group {
      display: flex;
      flex-direction: column;

      label {
        font-weight: bold;
        margin-bottom: 5px;
      }

      input {
        padding: 8px;
        border: 1px solid #ccc;
        border-radius: 4px;
      }
    }

    .submit-btn {
      padding: 10px;
      background-color: #007bff;
      color: white;
      border: none;
      border-radius: 4px;
      cursor: pointer;

      &:disabled {
        background-color: #6c757d;
        cursor: not-allowed;
      }
    }
  }

  .error-message {
    color: red;
    background-color: #f8d7da;
    padding: 10px;
    border-radius: 4px;
    margin-bottom: 20px;
  }

  .results-section {
    .stats-summary {
      background-color: #d4edda;
      padding: 15px;
      border-radius: 8px;
      margin-bottom: 20px;

      p {
        margin: 5px 0;
      }
    }

    .top-freelancers-table {
      table {
        width: 100%;
        border-collapse: collapse;
        margin-top: 10px;

        th, td {
          border: 1px solid #ddd;
          padding: 8px;
          text-align: left;
        }

        th {
          background-color: #f2f2f2;
          font-weight: bold;
        }

        tr:nth-child(even) {
          background-color: #f9f9f9;
        }
      }
    }

    .no-data {
      text-align: center;
      color: #666;
      font-style: italic;
    }
  }

  .loading-spinner {
    text-align: center;
    padding: 20px;
    color: #666;
  }
}
